 4	
 5	export async function recordAuditEvent(input: unknown) {
 6	  if (!input || typeof input !== "object") throw new Error("invalid audit event");
 7	  const event = { id: crypto.randomUUID(), payload: input, recordedAt: new Date().toISOString() };
 8	  await database.transaction((tx) => insertAuditEvent(tx, event));
 9	  await enqueueAuditExport({ eventId: event.id });
10	  return event;
11	}
